def validate_as_prior_version(self, prior):
    # Verificar que prior sea una instancia de InventoryValidator
    if not isinstance(prior, type(self)):
        raise TypeError("El inventario previo debe ser del mismo tipo")

    # Verificar que la fecha del prior sea anterior
    if prior.date >= self.date:
        raise ValueError("La fecha del inventario previo debe ser anterior")

    # Verificar que los productos existentes en prior existan en self
    # con cantidades mayores o iguales
    for product_id, prior_qty in prior.quantities.items():
        if product_id not in self.quantities:
            raise ValueError(f"Producto {product_id} no existe en inventario actual")
        if self.quantities[product_id] < prior_qty:
            raise ValueError(f"Cantidad de producto {product_id} es menor que en versión previa")

    # Verificar que los productos tengan los mismos atributos
    for product_id in prior.products:
        if product_id not in self.products:
            raise ValueError(f"Producto {product_id} no existe en inventario actual")
        if prior.products[product_id] != self.products[product_id]:
            raise ValueError(f"Atributos del producto {product_id} han cambiado")

    return True

def get_logical_path_map(inventory, version):
    logical_path_map = {}

    # Iterate through all versions up to and including target version
    for v in range(version + 1):
        if v in inventory:
            # For each file in this version
            for logical_path, content_file in inventory[v].items():
                # Initialize set if logical path not seen before
                if logical_path not in logical_path_map:
                    logical_path_map[logical_path] = set()

                # Add content file to set for this logical path
                logical_path_map[logical_path].add(content_file)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Validar el bloque de fijación en el inventario.

    Verificar la estructura del bloque de fijación y asegurarse de que solo se referencien los archivos listados en el manifiesto.
    """
    if not isinstance(fixity, dict):
        raise ValueError("El bloque de fijación debe ser un diccionario")

    # Verificar que tenga las claves requeridas
    required_keys = ["message_digest_algorithm", "message_digest"]
    for key in required_keys:
        if key not in fixity:
            raise ValueError(f"Falta la clave requerida '{key}' en el bloque de fijación")

    # Verificar que el algoritmo sea válido
    valid_algorithms = ["md5", "sha1", "sha256", "sha512"]
    if fixity["message_digest_algorithm"].lower() not in valid_algorithms:
        raise ValueError(f"Algoritmo de digest no válido. Debe ser uno de: {valid_algorithms}")

    # Verificar que message_digest sea un diccionario
    if not isinstance(fixity["message_digest"], dict):
        raise ValueError("message_digest debe ser un diccionario")

    # Verificar que solo se referencien archivos del manifiesto
    for file_path in fixity["message_digest"]:
        if file_path not in manifest_files:
            raise ValueError(f"El archivo '{file_path}' en el bloque de fijación no está listado en el manifiesto")

    # Verificar que los digests sean strings no vacíos
    for file_path, digest in fixity["message_digest"].items():
        if not isinstance(digest, str) or not digest:
            raise ValueError(f"Digest inválido para el archivo '{file_path}'")

    return True

