def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    Validar la jerarquía de la raíz de almacenamiento.

    Retorna:
        num_objects - número de objetos verificados
        good_objects - número de objetos verificados que se encontraron válidos
    """
    num_objects = 0
    good_objects = 0

    # Recorrer recursivamente la jerarquía
    for root, dirs, files in self.walk():
        for file in files:
            num_objects += 1

            try:
                # Validar objeto si está habilitado
                if validate_objects:
                    obj = self.get_object(file)

                    # Verificar digests si está habilitado
                    if check_digests:
                        if obj.verify_digest():
                            good_objects += 1
                        elif show_warnings:
                            print(f"Warning: Invalid digest for {file}")
                    else:
                        good_objects += 1

            except Exception as e:
                if show_warnings:
                    print(f"Warning: Error validating {file}: {str(e)}")
                continue

    return num_objects, good_objects

def find_path_type(path):
    import os
    import glob

    # Check if path exists
    if not os.path.exists(path):
        return "Error: Path does not exist"

    # Check if it's a directory
    if not os.path.isdir(path):
        if os.path.isfile(path):
            return "file"
        return "Error: Path is neither file nor directory"

    # Look for Namaste files starting with "0="
    namaste_files = glob.glob(os.path.join(path, "0=*"))

    if not namaste_files:
        return "Error: No Namaste files found"

    # Read content of first Namaste file
    try:
        with open(namaste_files[0], 'r') as f:
            content = f.read().strip()

        # Check content for OCFL root
        if "ocfl_" in content.lower():
            return "root"

        # Check content for OCFL object
        elif content.startswith("ocfl_object"):
            return "object"

    except Exception as e:
        return f"Error reading Namaste file: {str(e)}"

    return "Error: Unknown OCFL type"

